import React from "react";
import "./Contact.css"; // optional styling

const Contact = () => {
  return (
    <div className="contact-page">
      <h2>Contact Us</h2>
      <p>We’d love to hear from you! Reach us using the details below.</p>

      <div className="contact-details">
        <div>
          <h4>Email</h4>
          <p>support@healink.com</p>
        </div>

        <div>
          <h4>Phone</h4>
          <p>+91 98765 43210</p>
        </div>

        <div>
          <h4>Address</h4>
          <p>HEALink Headquarters,<br />Hyderabad, India</p>
        </div>
      </div>
    </div>
  );
};

export default Contact;
